def sort_order(path: str) -> tuple[int, str]:
    """Return a sortable priority for header/source scanning."""
    ext = os.path.splitext(path)[1].lower()
    priority = 0x20
    if "include/" in path and ext == ".h":
        priority = 0x00
    elif ext == ".h":
        priority = 0x10
    if "common" in path:
        priority -= 8
    return priority, path

