def find_c_cpp_files(root: str) -> list[str]:
    """Return C/C++ source and header paths under root."""
    out: list[str] = []
    for dirpath, dirnames, filenames in os.walk(root):
        for skip in (".git", "build"):
            if skip in dirnames:
                dirnames.remove(skip)
        for name in filenames:
            ext = os.path.splitext(name)[1].lower()
            if ext in {".c", ".cc", ".cpp", ".h", ".hpp"}:
                out.append(os.path.join(dirpath, name))
    out.sort(key=lambda p: os.path.splitext(p)[1].lower() in {".h", ".hpp"}, reverse=True)
    return out

class ConstraintChecker:
    """Check feasibility of solutions against bound and linear constraints."""

    def __init__(self, atol: float = 1e-6):
        self.atol = atol

    def within_bounds(self, x, lo, hi) -> bool:
        return (x >= lo - self.atol).all() and (x <= hi + self.atol).all()

    def satisfies_linear(self, A, x, b) -> bool:
        return ((A @ x) - b == 0).all()

def within_bounds(self, x, lo, hi) -> bool:
    """Return True iff every element of x lies in [lo, hi] (inclusive), within atol tolerance."""
    return (x >= lo - self.atol).all() and (x <= hi + self.atol).all()

def satisfies_linear(self, A, x, b) -> bool:
    """Return True iff A @ x equals b (within atol)."""
    return (abs((A @ x) - b) <= self.atol).all()

def read_text(path: str) -> str:
    """Read UTF-8 text from path. Returns an empty string if the file does not exist."""
    with open(path, 'r', encoding='utf-8') as f:
        return f.read()

def load_config(path: str) -> dict:
    """Load JSON config from path. Returns {} if the file does not exist."""
    try:
        raw = read_text(path)
    except FileNotFoundError:
        return {}
    return json.loads(raw)

def validate_config(cfg: dict) -> None:
