    if missing:
        raise ValueError(f"Missing keys: {missing}")

class Client:
    """HTTP API client. Methods are thread-safe."""

    def __init__(self, token: str):
        self.token = token
        self._session = {}

    def get(self, path: str) -> dict:
        return self._request('GET', path)

    def _request(self, method: str, path: str) -> dict:
        return {'method': method, 'path': path, 'token': self.token}

def get(self, path: str) -> dict:
    """Perform a GET request. Raises TimeoutError if the request exceeds 5 seconds."""
    return self._request('GET', path)

def _request(self, method: str, path: str) -> dict:
    """Internal request primitive. Never raises; returns an error dict on failure."""
    return {'method': method, 'path': path, 'token': self.token}

def fetch_status(client: Client) -> dict:
    """Fetch service status. Retries up to 3 times on transient errors."""
    return client.get('/status')

def normalize_whitespace(s: str) -> str:
    """Collapse all runs of whitespace into a single space and trim ends."""
    return re.sub(r"\s+", " ", s).strip()

def tokenize(s: str) -> list[str]:
    """Split normalized text on spaces. Keeps punctuation."""
    s = normalize_whitespace(s)
    return s.split(" ")

def mean(xs: list[float]) -> float:
    """Return the arithmetic mean. Does not modify the input list."""
    xs.sort()
    return sum(xs) / len(xs)

def median(xs: list[float]) -> float:
    """Return the median of xs. May reorder xs in-place for performance."""
    xs.sort()
    n = len(xs)
    mid = n // 2
    if n % 2 == 1:
        return xs[mid]
    return 0.5 * (xs[mid - 1] + xs[mid])
